import React from 'react';
import clsx from 'clsx';
import { useCssScope } from '../config-provider/hooks';
import { Text } from '../text';

import './style';

export interface BreadcrumbItemProps extends React.HTMLAttributes<HTMLDivElement> {
  /**
   * @internal
   */
  interactive?: boolean;
  /**
   * 最大宽度
   * @defaultValue 162
   * @privateRemarks 10 个中文字符 + '...' 刚好能显示下的宽度
   */
  maxWidth?: React.CSSProperties['maxWidth'];
}

export const BreadcrumbItem = React.forwardRef<HTMLDivElement, BreadcrumbItemProps>(
  ({ className, children, interactive = true, maxWidth, style, ...otherProps }, ref) => {
    const cssScope = useCssScope('breadcrumb-item');
    const mergedStyle = {
      ...style,
      maxWidth,
    };
    return (
      <Text
        as="div"
        className={clsx(cssScope(), className, interactive && cssScope('-interactive'))}
        ref={ref}
        style={mergedStyle}
        lineClamp={1}
        {...otherProps}
      >
        {children}
      </Text>
    );
  },
);
if (__DEV__) {
  BreadcrumbItem.displayName = 'BreadcrumbItem';
}
